180	    }
181	};
182	
183	static std::tuple<at::Tensor, at::Tensor, std::optional<at::Tensor>, std::optional<at::Tensor>>
184	sparse_attn_decode_interface(
185	    const at::Tensor &q,   // [b, s_q, h_q, d_qk]
186	    const at::Tensor &kv,   // [num_blocks, page_block_size, h_k, d_qk]
187	    const at::Tensor &indices,    // [b, s_q, topk]
188	    const std::optional<at::Tensor> &topk_length,   // [b, s_q]
189	    const std::optional<at::Tensor> &attn_sink, // [h_q]
190	    std::optional<at::Tensor> &tile_scheduler_metadata,   // num_sm_parts x (DecodingSchedMetaSize/4)
191	    std::optional<at::Tensor> &num_splits,                // batch_size + 1
192	    const std::optional<at::Tensor> &extra_kv,
193	    const std::optional<at::Tensor> &extra_indices,
194	    const std::optional<at::Tensor> &extra_topk_length,
195	    int d_v,
196	    float sm_scale
197	) {
198	    using bf16 = cutlass::bfloat16_t;
199	
200	    // Check the architecture
201	    Arch arch = Arch();
202	
203	    KU_CHECK_NDIM(q, 4);
204	    KU_CHECK_NDIM(kv, 4);
205	    KU_CHECK_NDIM(indices, 3);
206	
207	    int b = q.size(0);
208	    int s_q = q.size(1);
209	    int h_q = q.size(2);
210	    int d_qk = q.size(3);
211	    int num_blocks = kv.size(0);
212	    int page_block_size = kv.size(1);
213	    int h_kv = kv.size(2);
214	    int topk = indices.size(2);
215	
216	    bool have_topk_length = topk_length.has_value();
217	    bool have_extra_kcache = extra_kv.has_value();
218	    bool have_extra_topk_length = extra_topk_length.has_value();
219	    bool have_attn_sink = attn_sink.has_value();
220	
221	    int extra_num_blocks = 0, extra_page_block_size = 0, extra_topk = 0;
222	    if (have_extra_kcache) {
223	        extra_num_blocks = extra_kv->size(0);
224	        extra_page_block_size = extra_kv->size(1);
225	    }
226	    if (extra_indices.has_value()) {
227	        extra_topk = extra_indices->size(-1);
228	    }
229	
230	    // metadata sanity check
231	    TORCH_CHECK(b > 0);
232	    TORCH_CHECK(s_q > 0);
233	    TORCH_CHECK(h_q > 0);
234	    TORCH_CHECK(h_kv == 1, "Currently only MQA (i.e. h_kv == 1) is supported for sparse decoding");
235	    TORCH_CHECK(d_qk == 576 || d_qk == 512, "Only head_size_k == 576 or 512 is supported for sparse decoding");
236	    TORCH_CHECK(d_v == 512, "Only head_size_v == 512 is supported for sparse decoding");
237	    TORCH_CHECK(topk > 0);
238	
239	    if (have_extra_kcache) {
240	        TORCH_CHECK(extra_indices.has_value(), "extra_indices_in_kvcache must be provided when extra_kcache is provided for sparse attention");
241	    } else {
242	        TORCH_CHECK(!extra_indices.has_value(), "extra_indices_in_kvcache must not be provided when extra_k_cache is not provided");
243	        TORCH_CHECK(!extra_topk_length.has_value(), "extra_topk_length must not be provided when extra_k_cache is not provided");
244	    }
245	
246	    // Check device
247	    KU_CHECK_DEVICE(q);
248	    KU_CHECK_DEVICE(kv);
249	    KU_CHECK_DEVICE(indices);
250	    KU_CHECK_DEVICE(topk_length);
251	    KU_CHECK_DEVICE(attn_sink);
252	    KU_CHECK_DEVICE(tile_scheduler_metadata);
253	    KU_CHECK_DEVICE(num_splits);
254	    KU_CHECK_DEVICE(extra_kv);
255	    KU_CHECK_DEVICE(extra_indices);
256	    KU_CHECK_DEVICE(extra_topk_length);
257	
258	    // Check data type
259	    KU_CHECK_DTYPE(q, torch::kBFloat16);
260	    TORCH_CHECK(kv.dtype() == torch::kFloat8_e4m3fn || kv.dtype() == torch::kInt8 || kv.dtype() == torch::kUInt8, "key must have dtype fp8_e4m3fn, int8 or uint8");
261	    if (extra_kv.has_value()) {
262	        TORCH_CHECK(extra_kv->dtype() == torch::kFloat8_e4m3fn || extra_kv->dtype() == torch::kInt8 || extra_kv->dtype() == torch::kUInt8, "extra k cache must have dtype fp8_e4m3fn, int8 or uint8");
263	    }
264	    KU_CHECK_DTYPE(indices, torch::kInt32);
265	    KU_CHECK_DTYPE(topk_length, torch::kInt32);
266	    KU_CHECK_DTYPE(attn_sink, torch::kFloat32);
267	    KU_CHECK_DTYPE(tile_scheduler_metadata, torch::kInt32);
268	    KU_CHECK_DTYPE(num_splits, torch::kInt32);
269	    KU_CHECK_DTYPE(extra_indices, torch::kInt32);
270	    KU_CHECK_DTYPE(extra_topk_length, torch::kInt32);
271	    
272	    // Check layout
273	    KU_CHECK_LAST_DIM_CONTIGUOUS(q);
274	    KU_CHECK_LAST_DIM_CONTIGUOUS(kv);
275	    KU_CHECK_LAST_DIM_CONTIGUOUS(indices);
276	    KU_CHECK_CONTIGUOUS(topk_length);
277	    KU_CHECK_CONTIGUOUS(attn_sink);
278	
279	    KU_CHECK_CONTIGUOUS(tile_scheduler_metadata);
280	    KU_CHECK_CONTIGUOUS(num_splits);
281	
282	    KU_CHECK_LAST_DIM_CONTIGUOUS(extra_kv);
283	    KU_CHECK_LAST_DIM_CONTIGUOUS(extra_indices);
284	    KU_CHECK_CONTIGUOUS(extra_topk_length);
285	    
286	    // Check shape
287	    KU_CHECK_SHAPE(q, b, s_q, h_q, d_qk);
288	    {
289	        int bytes_per_token;
290	        if (d_qk == 576 && d_v == 512) {
291	            // V3.2 style
292	            bytes_per_token = 512 + 64*2 + (512/128)*4;
293	        } else if (d_qk == 512 && d_v == 512) {
294	            // MODEL1 style
295	            bytes_per_token = 448 + 64*2 + (448/64)*1 + 1;
296	        } else {
297	            TORCH_CHECK(false, "Unsupported head sizes for is_fp8_kvcache == True");
298	        }
299	        KU_CHECK_SHAPE(kv, num_blocks, page_block_size, h_kv, bytes_per_token);
300	        KU_CHECK_SHAPE(extra_kv, extra_num_blocks, extra_page_block_size, h_kv, bytes_per_token);
301	        TORCH_CHECK(kv.stride(1) == bytes_per_token, "The whole block must be contiguous when is_fp8_cache is True for kv cache");
302	        if (extra_kv.has_value()) {
303	            TORCH_CHECK(extra_kv->stride(1) == bytes_per_token, "The whole block must be contiguous when is_fp8_cache is True for extra kv cache");
304	        }
305	    }
306	    KU_CHECK_SHAPE(indices, b, s_q, topk);
307	    KU_CHECK_SHAPE(topk_length, b);
308	    KU_CHECK_SHAPE(attn_sink, h_q);
309	    KU_CHECK_SHAPE(extra_indices, b, s_q, extra_topk);
310	    KU_CHECK_SHAPE(extra_topk_length, b);
311	
312	    at::cuda::CUDAGuard device_guard{(char)q.get_device()};
313	    auto opts = q.options();
314	
315	    at::Tensor out = torch::empty({b, s_q, h_q, d_v}, opts);
316	    at::Tensor lse = torch::empty({b, s_q, h_q}, opts.dtype(at::kFloat));
317	
318	    ModelType model_type;
319	    if (d_qk == 576) {
320	        model_type = ModelType::V32;
321	    } else if (d_qk == 512) {
322	        model_type = ModelType::MODEL1;
323	    } else {
324	        TORCH_CHECK(false, "Unsupported d_qk: ", d_qk);
325	    }
326	
327	    std::vector<DecodeFeatures> features;
328	    if (h_q == 64) {
329	        features.push_back(DecodeFeatures::HEAD_64);
330	    } else if (h_q == 128) {
331	        features.push_back(DecodeFeatures::HEAD_128);
332	    } else {
333	        TORCH_CHECK(false, "Unsupported h_q: ", h_q);
334	    }
335	    if (d_qk == 576) {
336	        features.push_back(DecodeFeatures::HEAD_DIM_576);
337	    } else if (d_qk == 512) {
338	        features.push_back(DecodeFeatures::HEAD_DIM_512);
339	    } else {
340	        TORCH_CHECK(false, "Unsupported d_qk: ", d_qk);
341	    }
342	    if (model_type == ModelType::V32) {
343	        features.push_back(DecodeFeatures::V32_KVCACHE_FORMAT);
344	    } else if (model_type == ModelType::MODEL1) {
345	        features.push_back(DecodeFeatures::MODEL1_KVCACHE_FORMAT);
346	    } else {
347	        TORCH_CHECK(false, "Unsupported model type: ", (int)model_type);
348	    }
349	    if (have_attn_sink) {
350	        features.push_back(DecodeFeatures::ATTN_SINK);
351	    }
352	    if (have_topk_length) {
353	        features.push_back(DecodeFeatures::TOPK_LENGTH);
354	    }
355	    if (have_extra_kcache) {
356	        features.push_back(DecodeFeatures::EXTRA_KVCACHE);
357	    }
358	    if (have_extra_topk_length) {
359	        features.push_back(DecodeFeatures::EXTRA_TOPK_LENGTH);
360	    }
361	
362	    DecodeImplBase* impl;
363	    if (arch.is_sm100f()) {
364	        if (h_q == 64) {
365	            impl = new Decode_Sm100_Head64_Impl();
366	        } else if (h_q == 128) {
367	            if (d_qk == 576) {
368	                impl = new Decode_Sm100_Head64x2_Impl();
369	            } else if (d_qk == 512) {
370	                impl = new Decode_Sm100_Head128_Impl();
371	            } else {
372	                TORCH_CHECK(false, "Unsupported d_qk: ", d_qk);
373	            }
374	        } else {
375	            TORCH_CHECK(false, "Unsupported h_q: ", h_q);
376	        }
377	    } else if (arch.is_sm90a()) {
378	        impl = new Decode_Sm90_Impl();
379	    } else {
380	        TORCH_CHECK(false, "Unsupported architecture for sparse decode fwd");
381	    }
382	
383	    DecodeImplMeta impl_meta = impl->get_meta(h_q, s_q);
384	
385	    SparseAttnDecodeParams params = {
386	        b, s_q, h_q, h_kv, d_qk, d_v,
387	        sm_scale, sm_scale * LOG_2_E,
388	        num_blocks, page_block_size, topk,
389	        model_type,
390	
391	        (bf16*)q.data_ptr(),
392	        (bf16*)kv.data_ptr(),
393	        (int*)indices.data_ptr(),
394	        ku::get_optional_tensor_ptr<int>(topk_length),
395	        ku::get_optional_tensor_ptr<float>(attn_sink),
396	        (float*)lse.data_ptr(),
397	        (bf16*)out.data_ptr(),
398	
399	        extra_num_blocks, extra_page_block_size, extra_topk,
400	        ku::get_optional_tensor_ptr<bf16>(extra_kv),
401	        ku::get_optional_tensor_ptr<int>(extra_indices),
402	        ku::get_optional_tensor_ptr<int>(extra_topk_length),
403	
404	        int64_stride_to_int(q.stride(0)), int64_stride_to_int(q.stride(1)), int64_stride_to_int(q.stride(2)),
405	        int64_stride_to_int(kv.stride(0)), int64_stride_to_int(kv.stride(1)),
406	        int64_stride_to_int(indices.stride(0)), int64_stride_to_int(indices.stride(1)),
407	        int64_stride_to_int(lse.stride(0)), int64_stride_to_int(lse.stride(1)),
408	        int64_stride_to_int(out.stride(0)), int64_stride_to_int(out.stride(1)), int64_stride_to_int(out.stride(2)),
409	
410	        have_extra_kcache ? int64_stride_to_int(extra_kv->stride(0)) : 0,
411	        have_extra_kcache ? int64_stride_to_int(extra_kv->stride(1)) : 0,
412	        have_extra_kcache ? int64_stride_to_int(extra_indices->stride(0)) : 0,
413	        have_extra_kcache ? int64_stride_to_int(extra_indices->stride(1)) : 0,
414	        at::cuda::getCurrentCUDAStream().stream()
415	    };
416	
417	    // Get MLA metadata if necessary
418	    at::Tensor o_accum, lse_accum;
419	    if (!tile_scheduler_metadata.has_value()) {
420	        tile_scheduler_metadata = torch::empty({impl_meta.num_sm_parts, sizeof(DecodingSchedMeta)/4}, opts.dtype(torch::kInt32));
421	        num_splits = torch::empty({b+1}, opts.dtype(torch::kInt32));
422	        KU_CHECK_CONTIGUOUS(tile_scheduler_metadata);
423	        KU_CHECK_CONTIGUOUS(num_splits);
424	
425	        GetDecodeSchedMetaParams get_sched_meta_params = {
426	            b, s_q,
427	            impl_meta.block_size_topk,
428	            impl_meta.fixed_overhead_num_blocks,
429	            topk,
430	            extra_topk,
431	            ku::get_optional_tensor_ptr<int>(topk_length),
432	            ku::get_optional_tensor_ptr<int>(extra_topk_length),
433	            nullptr,
434	            (DecodingSchedMeta*)tile_scheduler_metadata->data_ptr(),
435	            num_splits->data_ptr<int>(),
436	            impl_meta.num_sm_parts,
437	            at::cuda::getCurrentCUDAStream().stream()
438	        };
439	        smxx::decode::run_get_decoding_sched_meta_kernel(get_sched_meta_params);
440	    }
441	    // Stick the metadata pointers to `params`
442	    KU_CHECK_DEVICE(tile_scheduler_metadata);
443	    KU_CHECK_DEVICE(num_splits);
444	    KU_CHECK_DTYPE(tile_scheduler_metadata, torch::kInt32);
445	    KU_CHECK_DTYPE(num_splits, torch::kInt32);
446	    KU_CHECK_CONTIGUOUS(tile_scheduler_metadata);
447	    KU_CHECK_CONTIGUOUS(num_splits);
448	    KU_CHECK_SHAPE(tile_scheduler_metadata, impl_meta.num_sm_parts, sizeof(DecodingSchedMeta)/sizeof(int));
449	    KU_CHECK_SHAPE(num_splits, b+1);
450	    params.tile_scheduler_metadata_ptr = (DecodingSchedMeta*)tile_scheduler_metadata->data_ptr();
451	    params.num_splits_ptr = num_splits->data_ptr<int>();
452	    params.num_sm_parts = impl_meta.num_sm_parts;
453	
454	    // Allocate intermediate buffers for split-KV
455	    const int total_num_splits = b + impl_meta.num_sm_parts;
456	    lse_accum = torch::empty({total_num_splits, s_q, h_q}, opts.dtype(at::kFloat));
457	    o_accum = torch::empty({total_num_splits, s_q, h_q, d_v}, opts.dtype(at::kFloat));
458	    KU_CHECK_CONTIGUOUS(lse_accum);
459	    KU_CHECK_CONTIGUOUS(o_accum);
460	    params.lse_accum = lse_accum.data_ptr<float>();
461	    params.o_accum = o_accum.data_ptr<float>();
462	    params.stride_lse_accum_split = int64_stride_to_int(lse_accum.stride(0));
463	    params.stride_lse_accum_s_q = int64_stride_to_int(lse_accum.stride(1));
464	    params.stride_o_accum_split = int64_stride_to_int(o_accum.stride(0));
465	    params.stride_o_accum_s_q = int64_stride_to_int(o_accum.stride(1));
466	    params.stride_o_accum_h_q = int64_stride_to_int(o_accum.stride(2));
467	
468	    impl->run(params, features);
469	    
470	    CombineParams combine_params = {
471	        b, s_q, h_q, d_v,
472	
473	        params.lse,
474	        params.out,
475	        params.stride_lse_b, params.stride_lse_s_q,
476	        params.stride_o_b, params.stride_o_s_q, params.stride_o_h_q,
477	
478	        params.lse_accum,
479	        params.o_accum,
480	        params.stride_lse_accum_split, params.stride_lse_accum_s_q,
481	        params.stride_o_accum_split, params.stride_o_accum_s_q, params.stride_o_accum_h_q,
482	
483	        params.tile_scheduler_metadata_ptr,
484	        params.num_splits_ptr,
485	        params.num_sm_parts,
486	
487	        ku::get_optional_tensor_ptr<float>(attn_sink),
488	        at::cuda::getCurrentCUDAStream().stream()
489	    };
490	    smxx::decode::run_flash_mla_combine_kernel<bf16>(combine_params);
491	
492	    delete impl;
493	
494	    return {out, lse.transpose(1, 2), tile_scheduler_metadata, num_splits};
495	}
